#include<bits/stdc++.h>
using namespace std;
struct node{
    int u, v, w;
    bool operator < (node x){
        return w < x.w;
    }
}tree[200005];
int f[200005];
int find(int x){
    if(f[x] == x)return x;
    return f[x] = find(f[x]);
}
int main()
{
    int ans = 0;
    int n, m;
    cin >> n >> m;
    for(int i = 1; i <= n; i++)f[i] = i;
    for(int i = 1; i <= m ; i++){
        cin >> tree[i].u >> tree[i].v >> tree[i].w;
    }
    sort(tree + 1, tree + m + 1);
    int cnt = 0;
    for(int i = 1; i <= m; i++){
        if(find(tree[i].u) != find(tree[i].v)){
            cnt++;
        	// cout << find(tree[i].u) << " " << find(tree[i].v) << endl;
            f[find(tree[i].v)] = find(tree[i].u);
            // f[tree[i].u] = find(tree[i].v);
            ans += tree[i].w;
        }
    }
    if(cnt != n - 1)return cout << "orz", 0;
    cout << ans;
}
